interface I18nContextType {
  language: Language
  setLanguage: (lang: Language) => void
  t: (key: string) => string
  tTeam: (teamKey: string) => string
  languages: LanguageInfo[]
}

const I18nContext = createContext<I18nContextType>({
  language: 'en',
  setLanguage: () => {},
  t: (key: string) => key,
  tTeam: (teamKey: string) => teamKey,
  languages: [],
})

export function I18nProvider({ children }: { children: ReactNode }) {
  const [language, setLanguage] = useState<Language>(() => {
    if (typeof window !== 'undefined') {
      // Priority 1: User has manually selected a language
      const saved = localStorage.getItem('netown_language') as Language | null
      if (saved && translations[saved]) return saved

      // Priority 2: CN IP → Chinese, all others → English
      // We check a flag set by GeoContext/ComplianceContext
      const isCN = localStorage.getItem('netown_is_cn') === 'true'
      if (isCN) return 'zh'

      return 'en'
    }
    return 'en'
  })

  // Auto-detect geo and set default language on first visit
  // This runs once after mount, after GeoContext is available
  const [geoChecked, setGeoChecked] = useState(false)

  useEffect(() => {
    if (geoChecked) return

    const detectAndSetLanguage = async () => {
      // If user already manually chose a language, respect that
      const saved = localStorage.getItem('netown_language')
      if (saved) {
        setGeoChecked(true)
        return
      }

      try {
        const response = await fetch('/api/geo/info')
        if (response.ok) {
          const data = await response.json()
          const isCN = data.isCN === true

          // Store CN flag for initial state on next page load
          localStorage.setItem('netown_is_cn', String(isCN))

          // CN → Chinese, all others → English
          const detectedLang: Language = isCN ? 'zh' : 'en'
          setLanguage(detectedLang)
          localStorage.setItem('netown_language', detectedLang)
        }
      } catch {
        // Fallback: check browser language
        const browserLang = navigator.language.toLowerCase()
        if (browserLang.startsWith('zh')) {
          localStorage.setItem('netown_is_cn', 'true')
          setLanguage('zh')
          localStorage.setItem('netown_language', 'zh')
        }
      } finally {
        setGeoChecked(true)
      }
    }

    detectAndSetLanguage()
  }, [geoChecked])

  const getNestedValue = (obj: Translation, path: string): string => {
    const keys = path.split('.')
    let current: Translation | string = obj
    for (const key of keys) {
      if (current && typeof current === 'object' && key in current) {
        current = current[key] as Translation | string
      } else {
        return path
      }
    }
    return typeof current === 'string' ? current : path
  }

  const handleSetLanguage = useCallback((lang: Language) => {
    setLanguage(lang)
    if (typeof window !== 'undefined') {
      localStorage.setItem('netown_language', lang)
    }
  }, [])

  const t = useCallback((key: string): string => {
    if (!key || typeof key !== 'string') return key || ''
    const langTranslations = translations[language]
    if (!langTranslations) return key
    const value = getNestedValue(langTranslations, key)
    if (value === key && language !== 'en') {
      const enValue = getNestedValue(translations.en, key)
      return enValue !== key ? enValue : key
    }
    return value
  }, [language])

  const tTeam = useCallback((teamKey: string): string => {
    return t(`teams.${teamKey}`)
  }, [t])

  return (
    <I18nContext.Provider value={{ language, setLanguage: handleSetLanguage, t, tTeam, languages }}>
      {children}
    </I18nContext.Provider>
  )
}

export function useI18n() {
  return useContext(I18nContext)
}
